  React.useEffect(() => { let ok = true; setLoading(true); Promise.allSettled([api.quote(assetSymbol), api.history(assetSymbol, range, range === '1d' ? '1h' : '1d'), api.technical(assetSymbol, range, range === '1d' ? '1h' : '1d'), api.analysis(assetSymbol), api.risk(assetSymbol), api.financials(assetSymbol), api.sentiment(assetSymbol), api.newsImpact(assetSymbol)]).then((results) => { if (!ok) return; const [q, h, tech, a, r, f, s, n] = results; if (q.status === 'fulfilled') setQuote(q.value); else console.error('Failed to load quote', q.reason); if (h.status === 'fulfilled') setHistory(h.value); else console.error('Failed to load history', h.reason); if (tech.status === 'fulfilled') setTechnical(tech.value); else console.error('Failed to load technical analysis', tech.reason); if (a.status === 'fulfilled') setAnalysis(a.value); else console.error('Failed to load analysis', a.reason); if (r.status === 'fulfilled') setRisk(r.value); else console.error('Failed to load risk', r.reason); if (f.status === 'fulfilled') setFinancials(f.value); else console.error('Failed to load financials', f.reason); if (s.status === 'fulfilled') setSentiment(s.value); else console.error('Failed to load sentiment', s.reason); if (n.status === 'fulfilled') setNews(n.value); else console.error('Failed to load news impact', n.reason); }).finally(() => ok && setLoading(false)); return () => { ok = false; }; }, [assetSymbol, range]);
  React.useEffect(() => { api.compare(compareSymbols).then(setCompare).catch((error) => console.error('Failed to load comparison', error)); }, [compareSymbols]);
  React.useEffect(() => { if (!smartWatchlist.length) { setWatchlistQuotes([]); return; } let ok = true; const controller = new AbortController(); api.quotes(smartWatchlist, { signal: controller.signal }).then((payload) => { if (ok) setWatchlistQuotes(payload.items); }).catch((error) => { if (!isApiRequestCanceled(error)) console.error('Failed to load watchlist quotes', error); }); return () => { ok = false; controller.abort(); }; }, [smartWatchlist]);
  React.useEffect(() => { const symbols = dedupeSymbols([...visibleOpportunitySymbols, ...smartWatchlist]); if (!symbols.length) { setSparklineMap({}); return; } let ok = true; api.sparklines(symbols).then((payload) => { if (!ok) return; const next: SparklineMap = {}; payload.items.forEach((item) => { next[item.symbol] = item; }); setSparklineMap(next); }).catch((error) => console.error('Failed to load seven day sparklines', error)); return () => { ok = false; }; }, [visibleOpportunitySymbols, smartWatchlist]);
  React.useEffect(() => { if (!portfolio.length) { setPortfolioEvaluation(null); return; } let ok = true; api.evaluatePortfolio(portfolio).then((payload) => { if (ok) setPortfolioEvaluation(payload); }).catch((error) => console.error('Failed to evaluate portfolio', error)); return () => { ok = false; }; }, [portfolio]);

  const selectedCategory = categories.find((category) => category.id === categoryId) ?? categories[0];
  const selectedAsset = selectedCategory?.assets.find((asset) => asset.symbol === assetSymbol) ?? selectedCategory?.assets[0];
  const categorySectors = sectors.filter((sectorItem) => sectorItem.assets.some((asset) => categoryIdFor(asset) === categoryId));
  const categoryAssetRows = categorySectors.flatMap((sectorItem) => sectorItem.assets).filter((asset, index, items) => categoryIdFor(asset) === categoryId && items.findIndex((item) => item.symbol === asset.symbol) === index);
