  const selectSearchAsset = (asset: AssetSearchItem) => { setCanonicalAsset(asset.canonical_symbol ?? asset.symbol); setAssetSearch(''); setSearchResults([]); setSearchError(''); setRecentSearches((items) => [asset, ...items.filter((item) => item.symbol !== asset.symbol)].slice(0, 8)); };
  const labelForSymbol = (symbol: string) => categories.flatMap((category) => category.assets).find((asset) => asset.symbol === symbol)?.label ?? searchResults.find((asset) => asset.symbol === symbol)?.label ?? recentSearches.find((asset) => asset.symbol === symbol)?.label ?? watchlistQuotes.find((item) => item.symbol === symbol)?.name ?? symbol;
