  const ask = () => api.ask(question, assetSymbol, language).then((payload) => { setAnswer(payload.answer); setAssistantHistory((items) => [{ question, response: payload }, ...items].slice(0, 5)); }).catch((error) => console.error('Failed to ask assistant', error));
