  const executiveMarketScore = marketCondition?.average_change_percent == null ? null : Math.max(0, Math.min(100, Math.round(50 + marketCondition.average_change_percent * 18)));
  const executiveMarketStatus = executiveMarketScore == null ? 'Awaiting data' : executiveMarketScore >= 75 ? 'Bullish' : executiveMarketScore >= 55 ? 'Neutral' : executiveMarketScore >= 40 ? 'Caution' : 'High Risk';
  const executiveBestOpportunity = opportunityScores[0];
