function Watchlist({ t, assets, quotes, sparklines, selectedSymbol, onSelect, onAdd, onRemove, onMove }: { t: Translation; assets: Asset[]; quotes: AssetQuote[]; sparklines: SparklineMap; selectedSymbol: string; onSelect: (symbol: string) => void; onAdd: () => void; onRemove: (symbol: string) => void; onMove: (symbol: string, direction: -1 | 1) => void; }) { const l = t === translations.th ? labels.th : labels.en; const [sortMode, setSortMode] = React.useState<'manual' | 'symbol' | 'change'>('manual'); const quoteMap = React.useMemo(() => new Map(quotes.map((item) => [item.symbol, item])), [quotes]); const sortedAssets = React.useMemo(() => [...assets].sort((a, b) => sortMode === 'symbol' ? a.symbol.localeCompare(b.symbol) : sortMode === 'change' ? ((quoteMap.get(b.symbol)?.change_percent ?? -999) - (quoteMap.get(a.symbol)?.change_percent ?? -999)) : 0), [assets, quoteMap, sortMode]); return <Panel title={t.watchlist} icon={<Radar size={18} />}><div className="mb-3 grid gap-2 sm:grid-cols-[1fr_auto]"><button className="about-button" onClick={onAdd}><Star size={16} />{l.favoriteSelected}</button><div className="select-shell"><select aria-label={l.sortWatchlist} value={sortMode} onChange={(event) => setSortMode(event.target.value as 'manual' | 'symbol' | 'change')}><option value="manual">{l.manual}</option><option value="symbol">Ticker</option><option value="change">{l.change}</option></select><ChevronDown size={16} /></div></div><div className="max-h-[560px] space-y-2 overflow-auto pr-1">{assets.length ? sortedAssets.map((asset, index) => { const originalIndex = assets.findIndex((item) => item.symbol === asset.symbol); const item = quoteMap.get(asset.symbol); const trend = item?.change_percent == null ? 'Unavailable' : item.change_percent >= 0 ? t.bullish : t.bearish; const signals = watchlistSignals(item); const signal = signals[0] ?? 'No signal'; const logoUrl = item?.provider_logo_url ?? item?.logo_url ?? item?.icon_url ?? null; return <div className="watchlist-row-pro" key={asset.symbol}><button className={`watch-button watchlist-main-action ${asset.symbol === selectedSymbol ? 'watch-button-active' : ''}`} onClick={() => onSelect(asset.symbol)}><AssetLogo symbol={asset.symbol} name={asset.label} logoUrl={logoUrl} size="sm" /><span className="watchlist-identity"><span className="watchlist-ticker">* {asset.symbol}</span><span className="watchlist-company">{asset.label}</span><span className="watchlist-price-line">{item ? `${formatNumber(item.price)} ${item.currency ?? ''} | ${formatPercent(item.change_percent)} | ${trend}` : l.loadingLiveQuote}</span></span><span className="watchlist-signal-badge">{signal}</span><span className="watchlist-spark"><AssetSparkline symbol={asset.symbol} sparkline={sparklines[asset.symbol]} compact /></span></button><div className="mt-2 flex flex-wrap gap-1">{signals.slice(1, 4).map((itemSignal) => <span className="pill" key={`${asset.symbol}-${itemSignal}`}>{itemSignal}</span>)}</div><div className="mt-2 flex gap-2"><button className="icon-button" aria-label={`${asset.symbol} ${l.moveUp}`} disabled={originalIndex <= 0 || sortMode !== 'manual'} onClick={() => onMove(asset.symbol, -1)}><ArrowUp size={14} /></button><button className="icon-button" aria-label={`${asset.symbol} ${l.moveDown}`} disabled={originalIndex < 0 || originalIndex === assets.length - 1 || sortMode !== 'manual'} onClick={() => onMove(asset.symbol, 1)}><ArrowDown size={14} /></button><button className="watch-button flex-1" onClick={() => onSelect(asset.symbol)}>{l.open}</button><button className="watch-button flex-1" onClick={() => onRemove(asset.symbol)}>{l.remove}</button></div>{sortMode !== 'manual' && index === 0 && <p className="mt-2 text-xs text-terminal-muted">{l.reorderHint}</p>}</div>; }) : <EmptyState message={l.watchlistEmpty} />}</div></Panel>; }
function PriceStrip({ t, quote, asset }: { t: Translation; quote: AssetQuote | null; asset?: Asset }) { const l = t === translations.th ? labels.th : labels.en; const positive = (quote?.change_percent ?? 0) >= 0; const profile = [quote?.exchange, quote?.sector, quote?.industry, quote?.country].filter(Boolean).join(' | '); return <div className="grid gap-3 md:grid-cols-4 executive-price-strip"><MetricCard level="hero" label={t.selectedAsset} value={quote?.name ?? asset?.label ?? quote?.symbol ?? t.loading} subvalue={profile || quote?.asset_type} icon={<Globe2 size={18} />} /><MetricCard level="hero" label={t.lastPrice} value={quote?.price == null ? 'Unavailable' : `${formatNumber(quote.price)} ${quote.currency ?? ''}`} subvalue={quote?.timestamp ? formatTime(quote.timestamp) : undefined} icon={<BarChart3 size={18} />} /><MetricCard label={t.dailyChange} value={formatPercent(quote?.change_percent)} subvalue={`${l.beta}: ${formatNumber(quote?.beta)}`} tone={positive ? 'green' : 'red'} icon={<LineChart size={18} />} /><MetricCard label={t.dataSource} value={quote?.source ?? 'Unavailable'} subvalue={quote?.logo_url ? l.logoAvailable : l.profileFromProvider} icon={<ShieldCheck size={18} />} /></div>; }
