function ChartPanel({ t, l, history, technical, activeIndicators, toggleIndicator, quote, range, setRange }: { t: Translation; l: typeof labels.th; history: AssetHistory | null; technical: TechnicalResponse | null; activeIndicators: string[]; toggleIndicator: (indicator: string) => void; quote: AssetQuote | null; range: string; setRange: (range: string) => void }) { const technicalSeries = technical?.series ?? []; const chartData = (technicalSeries.length ? technicalSeries : history?.points ?? []).map((point) => ({ ...point, label: new Date(String(point.time)).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }) })); const hasData = chartData.length > 0; const show = (name: string) => activeIndicators.includes(name); return <Panel title={t.priceChart} icon={<LineChart size={18} />}><div className="mb-3 flex flex-wrap items-center justify-between gap-2"><div className="flex flex-wrap gap-2">{ranges.map((item) => <button key={item} aria-pressed={range === item} className={`pill ${range === item ? 'watch-button-active' : ''}`} onClick={() => setRange(item)}>{item.toUpperCase()}</button>)}</div><span className="text-xs text-terminal-muted">{l.realData} | Zoom: drag bottom range</span></div><div className="mb-3 grid gap-2 text-xs text-terminal-muted sm:grid-cols-2"><span>{l.ohlc}: O {formatNumber(quote?.open)} H {formatNumber(quote?.high)} L {formatNumber(quote?.low)} C {formatNumber(quote?.price)}</span><span className="sm:text-right">{history?.points.length ?? 0} {t.points} | {technical?.source ?? history?.source ?? 'Unavailable'}</span></div><div className="mb-3 flex flex-wrap gap-2">{indicatorOptions.map((item) => <button key={item} type="button" aria-pressed={activeIndicators.includes(item)} className={`pill ${activeIndicators.includes(item) ? 'watch-button-active' : ''}`} onClick={() => toggleIndicator(item)}>{item}</button>)}</div><div className="h-[340px] w-full">{hasData ? <ResponsiveContainer><AreaChart data={chartData}><CartesianGrid stroke="#1e2b3f" strokeDasharray="3 3" /><XAxis dataKey="label" stroke="#7e8da8" tick={{ fontSize: 11 }} /><YAxis stroke="#7e8da8" tick={{ fontSize: 11 }} domain={['dataMin', 'dataMax']} /><Tooltip cursor={{ stroke: '#35d0ff', strokeDasharray: '3 3' }} contentStyle={{ background: '#0a101c', border: '1px solid #1e2b3f', borderRadius: 6, color: '#d9e7ff' }} /><Area type="monotone" dataKey="close" stroke="#35d0ff" strokeWidth={2} fill="#35d0ff22" />{show('EMA20') && <Area type="monotone" dataKey="ema20" stroke="#33d17a" strokeWidth={1.5} fill="transparent" dot={false} />}{show('EMA50') && <Area type="monotone" dataKey="ema50" stroke="#f7c948" strokeWidth={1.5} fill="transparent" dot={false} />}{show('EMA200') && <Area type="monotone" dataKey="ema200" stroke="#ff7a7a" strokeWidth={1.5} fill="transparent" dot={false} />}{show('SMA50') && <Area type="monotone" dataKey="sma50" stroke="#a78bfa" strokeWidth={1.5} fill="transparent" dot={false} />}{show('SMA200') && <Area type="monotone" dataKey="sma200" stroke="#94a3b8" strokeWidth={1.5} fill="transparent" dot={false} />}{show('VWAP') && <Area type="monotone" dataKey="vwap" stroke="#fb923c" strokeWidth={1.5} fill="transparent" dot={false} />}{show('Bollinger Bands') && <Area type="monotone" dataKey="bollinger_upper" stroke="#64748b" strokeWidth={1} fill="transparent" dot={false} />}{show('Bollinger Bands') && <Area type="monotone" dataKey="bollinger_lower" stroke="#64748b" strokeWidth={1} fill="transparent" dot={false} />}<Brush dataKey="label" height={24} stroke="#35d0ff" travellerWidth={8} /></AreaChart></ResponsiveContainer> : <EmptyState message={technical?.message ?? 'Historical data unavailable.'} />}</div><div className="mt-3 grid gap-2 text-xs text-terminal-muted sm:grid-cols-3"><span>RSI14: {formatNumber(technical?.indicators?.RSI14 as number | null)}</span><span>ATR: {formatNumber(technical?.indicators?.ATR as number | null)}</span><span>Trend: {technical?.interpretation?.trend ?? 'Unavailable'}</span></div></Panel>; }
function ChiefInvestmentCard({ t, language, quote, risk }: { t: Translation; language: Language; quote: AssetQuote | null; risk: RiskResponse | null }) {
  const thai = language === 'th';
  const hasMarketData = quote?.price != null && quote?.change_percent != null;
  const change = quote?.change_percent ?? 0;
  const riskScore = risk?.risk_score;
  const view = !hasMarketData ? 'Unavailable' : change > 1 ? t.bullish : change < -1 ? t.bearish : t.neutral;
  const recommendation = !hasMarketData || riskScore == null ? 'Wait' : riskScore >= 9 && change < -3 ? 'Sell' : riskScore >= 8 ? 'Avoid' : riskScore >= 7 ? 'Reduce' : change > 4 && riskScore <= 4 ? 'Buy' : change > 1.5 && riskScore <= 5 ? 'Accumulate' : change < -3 ? 'Wait' : 'Hold';
  const confidence = hasMarketData && riskScore != null ? t.medium : t.low;
  const horizon = riskScore == null ? (thai ? 'รอข้อมูล' : 'Awaiting data') : riskScore >= 7 ? (thai ? 'สั้น / ระมัดระวัง' : 'Short / cautious') : (thai ? 'ระยะกลางพร้อมติดตาม' : 'Medium term with monitoring');
  const riskLevel = riskScore == null ? 'Unavailable' : riskScore >= 7 ? (thai ? 'สูง' : 'High') : riskScore >= 4 ? (thai ? 'ปานกลาง' : 'Medium') : (thai ? 'ต่ำถึงปานกลาง' : 'Low to medium');
  const reasons = hasMarketData ? [`${t.dailyChange}: ${formatPercent(change)}`, `${t.riskScore}: ${riskScore ?? 'N/A'}/10`, `${t.dataSource}: ${quote?.source ?? 'Unavailable'}`] : [thai ? 'ยังไม่มีข้อมูลราคาจริงครบถ้วน' : 'Complete live quote data is not available'];
  const positives = hasMarketData ? [change >= 0 ? (thai ? 'แรงซื้อรายวันเป็นบวก' : 'Daily price action is positive') : (thai ? 'ราคาย่อตัว อาจรอจังหวะประเมินใหม่' : 'Pullback may create a setup to reassess'), quote?.market_cap != null ? (thai ? 'มีข้อมูลมูลค่าตลาดประกอบการประเมิน' : 'Market capitalization data is available') : (thai ? 'ยังต้องรอข้อมูลมูลค่าตลาด' : 'Market capitalization data is unavailable')] : [thai ? 'ยังไม่มีปัจจัยบวกที่ยืนยันได้จากข้อมูลสด' : 'No positive factor can be confirmed from live data yet'];
  const negatives = risk?.main_risks?.slice(0, 3) ?? [thai ? 'ข้อมูลความเสี่ยงยังไม่พร้อมใช้งาน' : 'Risk data is unavailable'];
  const monitor = thai ? ['ราคาและปริมาณเมื่อเทียบกับแนวโน้ม', 'คะแนนความเสี่ยงและความผันผวน', 'ข่าว ผลประกอบการ หรือเหตุการณ์มหภาค'] : ['Price and volume versus trend', 'Risk score and volatility', 'News, earnings, or macro events'];
  const summary = !hasMarketData ? (thai ? 'ข้อมูลยังไม่เพียงพอสำหรับการวิเคราะห์ที่น่าเชื่อถือ' : 'There is currently insufficient market data to produce a reliable analysis.') : thai ? `คำแนะนำเชิงการศึกษา: ${recommendation}. ภาพรวมของ ${quote?.symbol ?? 'สินทรัพย์นี้'} อยู่ในโซน${view} โดยต้องอ่านร่วมกับความผันผวน สภาพคล่อง ข่าว และขนาดสถานะเสมอ` : `Educational recommendation: ${recommendation}. ${quote?.symbol ?? 'This asset'} currently screens as ${view.toLowerCase()}, but volatility, liquidity, news, and position size must be reviewed together.`;
  return <Panel title={t.chiefInvestmentAI} icon={<BriefcaseBusiness size={18} />}><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-5"><StatusTile label="Recommendation" value={recommendation} /><StatusTile label={t.confidence} value={confidence} /><StatusTile label={thai ? 'Investment Horizon' : 'Investment Horizon'} value={horizon} /><StatusTile label={thai ? 'Risk Level' : 'Risk Level'} value={riskLevel} /><StatusTile label={t.volatility} value={risk?.volatility_level ?? 'Unavailable from provider'} /></div><p className="mt-4 rounded-md bg-terminal-panel2 p-3 text-sm leading-6 text-white"><span className="font-semibold text-terminal-cyan">{t.aiSummary}: </span>{summary}</p><div className="mt-3 grid gap-3 lg:grid-cols-4"><ListBlock title={thai ? 'เหตุผลหลัก' : 'Key Reasons'} items={reasons} /><ListBlock title={thai ? 'ปัจจัยบวก' : 'Positive Factors'} items={positives} /><ListBlock title={thai ? 'ปัจจัยลบ' : 'Negative Factors'} items={negatives} /><ListBlock title={thai ? 'สิ่งที่ต้องติดตาม' : 'Things to Monitor'} items={monitor} /></div><p className="mt-3 text-xs text-terminal-muted">{thai ? 'ข้อมูลนี้เป็นการศึกษาเท่านั้น ไม่ใช่คำแนะนำทางการเงิน ผู้ใช้ต้องตัดสินใจเองและกำหนดแผนรับมือก่อนลงทุน' : 'Educational analysis only. Not financial advice. The user remains responsible for decisions and risk planning.'}</p></Panel>;
}function AICommittee({ t, language, quote, risk, financials }: { t: Translation; language: Language; quote: AssetQuote | null; risk: RiskResponse | null; financials: FinancialsResponse | null }) { const thai = language === 'th'; const change = quote?.change_percent; const riskScore = risk?.risk_score; const vote = riskScore == null ? (thai ? 'รอข้อมูล' : 'Wait for data') : riskScore >= 7 ? (thai ? 'ลดความเสี่ยง' : 'Reduce risk') : change != null && change > 1 ? (thai ? 'น่าติดตาม' : 'Watch closely') : (thai ? 'รอจังหวะ' : 'Wait for setup'); const cards = [{ title: t.technicalAnalyst, evidence: `Price ${formatNumber(quote?.price)} | 1D ${formatPercent(change)}`, confidence: quote?.price == null ? t.low : t.medium, reasoning: thai ? 'ประเมินจากราคาล่าสุดและแรงเคลื่อนไหวรายวัน' : 'Uses latest price and daily movement.', pros: change != null && change > 0 ? [thai ? 'โมเมนตัมระยะสั้นเป็นบวก' : 'Short-term momentum is positive'] : [], cons: change != null && change < 0 ? [thai ? 'ราคายังอยู่ภายใต้แรงกดดัน' : 'Price remains under pressure'] : [] }, { title: t.fundamentalAnalyst, evidence: financials?.applicable ? `P/E ${formatNumber(financials.facts?.pe as number | null)} | ROE ${formatNumber(financials.facts?.roe as number | null)}` : (thai ? 'ไม่มีงบการเงินสำหรับสินทรัพย์นี้' : 'No corporate statements for this asset type'), confidence: financials?.status === 'partial' ? t.medium : t.low, reasoning: thai ? 'ใช้เฉพาะข้อมูลพื้นฐานที่ผู้ให้บริการส่งกลับ' : 'Uses only provider-returned fundamentals.', pros: financials?.applicable ? [thai ? 'มีข้อมูลบางส่วนให้ตรวจสอบ' : 'Some fundamentals are available'] : [], cons: [thai ? 'ข้อมูลอาจไม่ครบทุกงวด' : 'Provider data may be incomplete'] }, { title: t.riskOfficer, evidence: `${t.riskScore} ${riskScore ?? 'N/A'} | ${t.volatility} ${risk?.volatility_level ?? 'N/A'}`, confidence: riskScore == null ? t.low : t.medium, reasoning: thai ? 'คะแนนสูงหมายถึงต้องลดขนาดสถานะหรือรอจังหวะ' : 'Higher scores require smaller sizing or patience.', pros: riskScore != null && riskScore <= 5 ? [thai ? 'ความเสี่ยงยังอยู่ในกรอบรับได้' : 'Risk is still moderate'] : [], cons: riskScore != null && riskScore >= 7 ? [thai ? 'เสี่ยงสูง ต้องมีแผนรับมือ' : 'High risk requires a plan'] : [] }]; return <Panel title={t.aiCommittee} icon={<Brain size={18} />}><div className="mb-4 rounded-md bg-terminal-panel2 p-3 text-sm leading-6 text-white"><span className="font-semibold text-terminal-cyan">Chief AI: </span>{thai ? `มุมมองรวมคือ "${vote}" เพราะข้อมูลราคา ความเสี่ยง และปัจจัยพื้นฐานยังต้องอ่านร่วมกัน ไม่ใช่สัญญาณซื้อขายโดยตรง` : `Committee vote is "${vote}" because price, risk, and fundamentals must be read together. This is not a direct trading signal.`}</div><div className="grid gap-3 lg:grid-cols-3">{cards.map((card) => <div className="rounded-md border border-terminal-border bg-terminal-panel2 p-3" key={card.title}><div className="flex items-start justify-between gap-3"><h3 className="text-sm font-semibold text-white">{card.title}</h3><span className="pill">{card.confidence}</span></div><StatusRow label={thai ? 'โหวต' : 'Vote'} value={vote} /><p className="mt-2 text-xs text-terminal-muted">{thai ? 'หลักฐาน' : 'Evidence'}: {card.evidence}</p><p className="mt-2 text-xs leading-5 text-terminal-text">{thai ? 'เหตุผล' : 'Reasoning'}: {card.reasoning}</p><p className="mt-2 text-xs text-terminal-green">{thai ? 'ข้อดี' : 'Pros'}: {(card.pros.length ? card.pros : [thai ? 'ยังไม่มีหลักฐานเด่น' : 'No strong positive evidence yet']).join(', ')}</p><p className="mt-1 text-xs text-terminal-red">{thai ? 'ข้อเสีย' : 'Cons'}: {(card.cons.length ? card.cons : [thai ? 'ยังต้องติดตามข้อมูลเพิ่ม' : 'Needs more evidence']).join(', ')}</p></div>)}</div></Panel>; }
function RiskPanel({ t, risk }: { t: Translation; risk: RiskResponse | null }) { const trend = risk?.risk_score == null ? 'Unavailable' : risk.risk_score >= 7 ? 'Rising / สูงขึ้น' : risk.risk_score >= 4 ? 'Stable / ทรงตัว' : 'Contained / ควบคุมได้'; return <Panel title={t.riskAnalysis} icon={<AlertTriangle size={18} />}><StatusRow label={t.volatility} value={risk?.volatility_level ?? t.loading} /><StatusRow label={t.riskScore} value={risk?.risk_score == null ? 'Unavailable' : `${risk.risk_score} / 10`} /><StatusRow label="Risk Trend / แนวโน้มความเสี่ยง" value={trend} /><div className="mb-4 grid gap-2">{(risk?.categories ?? []).map((item) => <div className="rounded-md bg-terminal-panel2 p-3" key={item.category}><div className="flex items-center justify-between gap-3"><span className="text-sm font-semibold text-white">{item.category}</span><span className="text-sm text-terminal-amber">{item.score}/10</span></div><div className="mt-2 grid gap-2 text-xs text-terminal-muted sm:grid-cols-3"><span>Probability / โอกาสเกิด: {item.probability}</span><span>Severity / ความรุนแรง: {item.severity}</span><span>Trend / แนวโน้ม: {item.trend ?? 'stable'}</span></div><p className="mt-2 text-xs leading-5 text-terminal-muted">Evidence / หลักฐาน: {item.evidence}</p><p className="mt-1 text-xs leading-5 text-terminal-cyan">Mitigation / แผนรับมือ: {item.mitigation}</p></div>)}</div><p className="mb-4 rounded-md bg-terminal-panel2 p-3 text-sm leading-6 text-terminal-muted">Historical Context / บริบทย้อนหลัง: {(risk?.facts ?? []).join(' ') || 'Unavailable'}</p><ListBlock title={t.mainRisk} items={risk?.main_risks} /><ListBlock title={t.actionPlan} items={risk?.risk_controls} /></Panel>; }
function FinancialPanel({ t, financials }: { t: Translation; financials: FinancialsResponse | null }) { if (!financials?.applicable) return <Panel title={t.financialStatements} icon={<Building2 size={18} />}><p className="text-sm leading-6 text-white">{financials?.message_th ?? financials?.message ?? t.notApplicable}</p>{financials?.alternative_fundamentals && <p className="mt-3 text-sm text-terminal-muted">{t.alternativeFundamentals}: {financials.alternative_fundamentals.focus_areas.join(', ')}</p>}</Panel>; const facts = financials.facts ?? {}; const metricRows = [{ label: t.revenue, value: facts.revenue, tone: 'health-green', note: 'Revenue trend' }, { label: 'Net Profit', value: facts.net_profit, tone: 'health-emerald', note: 'Net profit trend' }, { label: 'ROE', value: facts.roe, tone: 'health-gold', note: 'Return on equity' }, { label: 'ROA', value: facts.roa, tone: 'health-blue', note: 'Return on assets' }, { label: 'Dividend Yield', value: facts.dividend_yield, tone: 'health-purple', note: 'Dividend yield' }, { label: 'Free Cash Flow', value: facts.free_cash_flow, tone: 'health-cyan', note: 'Cash flow quality' }, { label: 'P/E', value: facts.pe, tone: 'health-orange', note: 'Valuation risk' }, { label: 'Current Ratio', value: facts.current_ratio, tone: 'health-teal', note: 'Liquidity strength' }, { label: 'Debt/Equity', value: facts.debt_to_equity, tone: 'health-red', note: 'Balance sheet leverage' }]; const available = metricRows.filter((row) => typeof row.value === 'number') as Array<{ label: string; value: number; tone: string; note: string }>; const rawScore = available.length ? Math.round(Math.min(10, Math.max(1, available.reduce((sum, row) => sum + (row.label === 'Debt/Equity' ? Math.max(1, 10 - Math.min(9, Math.abs(row.value))) : Math.min(10, Math.max(1, Math.abs(row.value) > 1 ? 6 : 6 + row.value * 4))), 0) / available.length)) * 10) / 10 : null; const healthLabel = rawScore == null ? 'Unavailable' : rawScore >= 8 ? 'Excellent' : rawScore >= 6.5 ? 'Good' : rawScore >= 5 ? 'Average' : 'Weak'; return <Panel title={t.financialStatements} icon={<Building2 size={18} />}><div className="financial-health-grid">{metricRows.map((row) => <div className={'financial-health-card ' + row.tone} key={row.label}><div className="health-icon" aria-hidden="true" /><p>{row.label}</p><b>{typeof row.value === 'number' ? formatCompactNumber(row.value) : 'Unavailable'}</b><small>{row.note}</small></div>)}</div><div className={'financial-health-summary ' + healthLabel.toLowerCase()}><span>Financial Health</span><b>{healthLabel}</b><strong>{rawScore == null ? 'N/A' : String(rawScore) + '/10'}</strong><p>{financials.interpretation?.summary ?? financials.message ?? 'Provider financial analysis is limited.'}</p></div><ListBlock title={'Risks'} items={financials.risks} /><ListBlock title={t.actionPlan} items={financials.cautious_action_plan} /></Panel>; }
function CompactChiefInvestmentCard({ t, language, quote, risk }: { t: Translation; language: Language; quote: AssetQuote | null; risk: RiskResponse | null }) {
  const thai = language === 'th';
  const hasMarketData = quote?.price != null && quote?.change_percent != null;
  const change = quote?.change_percent ?? 0;
  const riskScore = risk?.risk_score;
  const view = !hasMarketData ? 'Unavailable' : change > 1 ? t.bullish : change < -1 ? t.bearish : t.neutral;
  const recommendation = !hasMarketData || riskScore == null ? 'Wait' : riskScore >= 9 && change < -3 ? 'Sell' : riskScore >= 8 ? 'Avoid' : riskScore >= 7 ? 'Reduce' : change > 4 && riskScore <= 4 ? 'Buy' : change > 1.5 && riskScore <= 5 ? 'Accumulate' : change < -3 ? 'Wait' : 'Hold';
  const confidence = hasMarketData && riskScore != null ? t.medium : t.low;
  const horizon = riskScore == null ? (thai ? 'รอข้อมูล' : 'Awaiting data') : riskScore >= 7 ? (thai ? 'สั้น / ระวัง' : 'Short / cautious') : (thai ? 'กลาง / ติดตาม' : 'Medium / monitor');
  const riskLevel = riskScore == null ? 'Unavailable' : riskScore >= 7 ? (thai ? 'เสี่ยงสูง' : 'High') : riskScore >= 4 ? (thai ? 'ปานกลาง' : 'Medium') : (thai ? 'ควบคุมได้' : 'Contained');
  const positives = hasMarketData ? [change > 0 ? (thai ? 'ราคาเคลื่อนไหวเป็นบวกในวันล่าสุด' : 'Latest daily move is positive') : (thai ? 'ยังไม่มีแรงบวกเด่นจากราคาล่าสุด' : 'No strong positive price signal yet'), quote?.market_cap ? (thai ? 'มีข้อมูลมูลค่าตลาดประกอบการประเมิน' : 'Market cap is available for context') : (thai ? 'รอมูลค่าตลาดจากผู้ให้บริการ' : 'Market cap is unavailable')] : [thai ? 'รอข้อมูลสดเพิ่มเติม' : 'Awaiting live market data'];
  const negatives = risk?.main_risks?.slice(0, 3) ?? [thai ? 'ข้อมูลความเสี่ยงยังไม่พร้อม' : 'Risk data is unavailable'];
  const monitor = risk?.risk_controls?.[0] ?? (thai ? 'ติดตามราคา ความผันผวน ข่าว และขนาดสถานะ' : 'Monitor price, volatility, news, and position size');
  const summary = !hasMarketData ? (thai ? 'ข้อมูลยังไม่เพียงพอสำหรับมุมมองที่น่าเชื่อถือ จึงควรรอข้อมูลจากผู้ให้บริการก่อนตัดสินใจ' : 'There is not enough live market data for a reliable view. Wait for provider data before making decisions.') : thai ? `${quote?.symbol ?? 'สินทรัพย์นี้'} อยู่ในภาพ ${view} พร้อมคำแนะนำเชิงการศึกษาแบบ ${recommendation}. ควรอ่านร่วมกับความเสี่ยง ข่าว และขนาดสถานะเสมอ` : `${quote?.symbol ?? 'This asset'} currently screens as ${view.toLowerCase()} with an educational ${recommendation} stance. Read it together with risk, news, and position sizing.`;
  return <Panel title={t.chiefInvestmentAI} icon={<BriefcaseBusiness size={18} />}><div className="fs300a-chief-grid"><StatusTile label="Recommendation" value={recommendation} /><StatusTile label={t.confidence} value={confidence} /><StatusTile label="Investment Horizon" value={horizon} /><StatusTile label="Risk Level" value={riskLevel} /></div><p className="fs300a-summary"><span>{t.aiSummary}: </span>{summary}</p><div className="fs300a-factor-grid"><StatusRow label={thai ? 'ปัจจัยบวกหลัก' : 'Top Positive'} value={positives[0]} /><StatusRow label={thai ? 'ปัจจัยลบหลัก' : 'Top Negative'} value={negatives[0]} /><StatusRow label={thai ? 'สิ่งที่ต้องติดตาม' : 'Top Watch Item'} value={monitor} /></div><details className="fs300a-details"><summary>{thai ? 'ดูบทวิเคราะห์เต็ม' : 'View Full Analysis'}</summary><div className="mt-3 grid gap-3 lg:grid-cols-3"><ListBlock title={thai ? 'ปัจจัยบวก' : 'Positive Factors'} items={positives} /><ListBlock title={thai ? 'ปัจจัยลบ' : 'Negative Factors'} items={negatives} /><ListBlock title={thai ? 'แผนติดตาม' : 'Watch Plan'} items={[monitor, thai ? 'กำหนดแผนรับมือก่อนลงทุน' : 'Define a risk plan before investing']} /></div><p className="mt-3 text-xs text-terminal-muted">{thai ? 'ข้อมูลนี้เป็นการศึกษา ไม่ใช่คำแนะนำทางการเงิน' : 'Educational analysis only. Not financial advice.'}</p></details></Panel>;
}

function CompactAICommittee({ t, language, quote, risk, financials }: { t: Translation; language: Language; quote: AssetQuote | null; risk: RiskResponse | null; financials: FinancialsResponse | null }) {
  const thai = language === 'th';
  const change = quote?.change_percent;
  const riskScore = risk?.risk_score;
  const vote = riskScore == null ? (thai ? 'รอข้อมูล' : 'Wait for data') : riskScore >= 7 ? (thai ? 'ลดความเสี่ยง' : 'Reduce risk') : change != null && change > 1 ? (thai ? 'น่าติดตาม' : 'Watch closely') : (thai ? 'รอจังหวะ' : 'Wait for setup');
  const rows = [{ role: 'Chief AI', vote, evidence: quote?.symbol ?? 'Selected asset' }, { role: t.technicalAnalyst, vote: change == null ? (thai ? 'รอข้อมูล' : 'Wait') : change > 0 ? (thai ? 'บวก' : 'Positive') : (thai ? 'ระวัง' : 'Cautious'), evidence: `1D ${formatPercent(change)}` }, { role: t.fundamentalAnalyst, vote: financials?.applicable ? (thai ? 'ตรวจสอบต่อ' : 'Review') : (thai ? 'ไม่เกี่ยวข้อง' : 'N/A'), evidence: financials?.applicable ? `P/E ${formatNumber(financials.facts?.pe as number | null)}` : (thai ? 'ไม่มีงบการเงิน' : 'No statements') }, { role: t.riskOfficer, vote: riskScore == null ? (thai ? 'รอข้อมูล' : 'Wait') : riskScore >= 7 ? (thai ? 'เสี่ยงสูง' : 'High risk') : (thai ? 'ควบคุมได้' : 'Contained'), evidence: `${riskScore ?? 'N/A'}/10` }];
  return <Panel title={t.aiCommittee} icon={<Brain size={18} />}><div className="fs300a-committee-head"><span>Chief AI</span><strong>{vote}</strong><small>{t.confidence}: {riskScore == null ? t.low : t.medium}</small></div><div className="fs300a-committee-grid">{rows.map((row) => <div key={row.role}><span>{row.role}</span><b>{row.vote}</b><small>{row.evidence}</small></div>)}</div><StatusRow label={thai ? 'ฉันทามติรวม' : 'Overall Consensus'} value={thai ? `${vote} โดยอ่านราคา ความเสี่ยง และพื้นฐานร่วมกัน` : `${vote}; price, risk, and fundamentals should be read together`} /><details className="fs300a-details"><summary>{thai ? 'ดูรายละเอียดกรรมการ' : 'View Details'}</summary><div className="mt-3 grid gap-2">{rows.map((row) => <p className="rounded-md bg-terminal-panel2 p-2 text-xs text-terminal-muted" key={`${row.role}-detail`}><b className="text-white">{row.role}</b>: {row.vote} | {row.evidence}</p>)}</div></details></Panel>;
}

function CompactRiskPanel({ t, risk, language }: { t: Translation; risk: RiskResponse | null; language: Language }) {
  const thai = language === 'th';
  const trend = risk?.risk_score == null ? 'Unavailable' : risk.risk_score >= 7 ? (thai ? 'สูงขึ้น' : 'Rising') : risk.risk_score >= 4 ? (thai ? 'ทรงตัว' : 'Stable') : (thai ? 'ควบคุมได้' : 'Contained');
  const categories = risk?.categories ?? [];
  const topRisks = risk?.main_risks?.slice(0, 3) ?? categories.slice(0, 3).map((item) => `${item.category}: ${item.score}/10`);
  const mitigations = risk?.risk_controls?.slice(0, 3) ?? categories.slice(0, 3).map((item) => item.mitigation);
  return <Panel title={t.riskAnalysis} icon={<AlertTriangle size={18} />}><div className="fs300a-risk-score"><span>{t.riskScore}</span><strong>{risk?.risk_score == null ? 'N/A' : `${risk.risk_score}/10`}</strong><small>{t.volatility}: {risk?.volatility_level ?? t.loading}</small><small>{thai ? 'แนวโน้ม' : 'Trend'}: {trend}</small></div><div className="fs300a-risk-columns"><ListBlock title={t.mainRisk} items={topRisks} /><ListBlock title={t.actionPlan} items={mitigations} /></div><details className="fs300a-details"><summary>{thai ? 'ดูความเสี่ยงทั้งหมด' : 'View Full Risk Analysis'}</summary><div className="mt-3 grid gap-2">{categories.map((item) => <div className="rounded-md bg-terminal-panel2 p-2" key={item.category}><div className="flex items-center justify-between gap-3"><span className="text-xs font-semibold text-white">{item.category}</span><span className="text-xs text-terminal-amber">{item.score}/10</span></div><p className="mt-1 text-xs text-terminal-muted">{item.evidence}</p><p className="mt-1 text-xs text-terminal-cyan">{item.mitigation}</p></div>)}</div><p className="mt-3 text-xs text-terminal-muted">{(risk?.facts ?? []).join(' ') || 'Historical context unavailable.'}</p></details></Panel>;
}

function CompactFinancialPanel({ t, financials }: { t: Translation; financials: FinancialsResponse | null }) {
  if (!financials?.applicable) return <Panel title={t.financialStatements} icon={<Building2 size={18} />}><p className="text-sm leading-6 text-white">{financials?.message_th ?? financials?.message ?? t.notApplicable}</p>{financials?.alternative_fundamentals && <p className="mt-3 text-sm text-terminal-muted">{t.alternativeFundamentals}: {financials.alternative_fundamentals.focus_areas.join(', ')}</p>}</Panel>;
  const facts = financials.facts ?? {};
  const metricRows = [{ label: t.revenue, value: facts.revenue, tone: 'health-green', note: 'Revenue' }, { label: 'Net Profit', value: facts.net_profit, tone: 'health-emerald', note: 'Profit' }, { label: 'ROE', value: facts.roe, tone: 'health-gold', note: 'Quality' }, { label: 'ROA', value: facts.roa, tone: 'health-blue', note: 'Assets' }, { label: 'Dividend', value: facts.dividend_yield, tone: 'health-purple', note: 'Yield' }, { label: 'FCF', value: facts.free_cash_flow, tone: 'health-cyan', note: 'Cash flow' }, { label: 'P/E', value: facts.pe, tone: 'health-orange', note: 'Value' }, { label: 'D/E', value: facts.debt_to_equity, tone: 'health-red', note: 'Debt' }];
  const available = metricRows.filter((row) => typeof row.value === 'number') as Array<{ label: string; value: number; tone: string; note: string }>;
  const rawScore = available.length ? Math.round(Math.min(10, Math.max(1, available.reduce((sum, row) => sum + (row.label === 'D/E' ? Math.max(1, 10 - Math.min(9, Math.abs(row.value))) : Math.min(10, Math.max(1, Math.abs(row.value) > 1 ? 6 : 6 + row.value * 4))), 0) / available.length)) * 10) / 10 : null;
  const healthLabel = rawScore == null ? 'Unavailable' : rawScore >= 8 ? 'Excellent' : rawScore >= 6.5 ? 'Good' : rawScore >= 5 ? 'Average' : 'Weak';
  return <Panel title={t.financialStatements} icon={<Building2 size={18} />}><div className={'financial-health-summary fs300a-financial-summary ' + healthLabel.toLowerCase()}><span>Financial Health</span><b>{healthLabel}</b><strong>{rawScore == null ? 'N/A' : String(rawScore) + '/10'}</strong><p>{financials.interpretation?.summary ?? financials.message ?? 'Provider financial analysis is limited.'}</p></div><div className="financial-health-grid fs300a-financial-grid">{metricRows.map((row) => <div className={'financial-health-card ' + row.tone} key={row.label}><p>{row.label}</p><b>{typeof row.value === 'number' ? formatCompactNumber(row.value) : 'Unavailable'}</b><small>{row.note}</small></div>)}</div><details className="fs300a-details"><summary>View Details</summary><div className="mt-3 grid gap-3 lg:grid-cols-2"><ListBlock title="Risks" items={financials.risks} /><ListBlock title={t.actionPlan} items={financials.cautious_action_plan} /></div></details></Panel>;
}

function SentimentPanel({ l, sentiment, marketCondition }: { t: Translation; l: typeof labels.th; sentiment: SentimentResponse | null; marketCondition: MarketConditionResponse | null }) {
  const metrics = marketCondition?.metrics ?? [];
  const average = marketCondition?.average_change_percent;
  const composite = average == null ? null : Math.max(0, Math.min(100, Math.round(50 + average * 18)));
  const mood = composite == null
    ? { label: 'รอข้อมูล', phase: 'ข้อมูลไม่พอ', className: 'mood-neutral', explanation: 'ระบบยังไม่มีข้อมูลตลาดเพียงพอสำหรับสรุปภาวะตลาดอย่างน่าเชื่อถือ ควรรอข้อมูลจากผู้ให้บริการก่อนตัดสินใจ', actions: ['รอข้อมูลยืนยันเพิ่มเติม', 'หลีกเลี่ยงการเร่งเปิดสถานะ', 'ติดตามข่าวเศรษฐกิจ'] }
    : composite >= 85
      ? { label: 'เชิงบวกมาก', phase: 'Risk-On', className: 'mood-on', explanation: 'ภาวะตลาดโดยรวมมีแรงหนุนเชิงบวกจากข้อมูลที่มีอยู่ แต่ยังควรกำหนดแผนรับมือหากสัญญาณเปลี่ยนเร็ว', actions: ['ติดตามสินทรัพย์ที่แข็งแรงกว่าตลาด', 'เพิ่มน้ำหนักอย่างค่อยเป็นค่อยไป', 'กำหนดจุดลดความเสี่ยงล่วงหน้า'] }
      : composite >= 75
        ? { label: 'เชิงบวก', phase: 'บวก', className: 'mood-on', explanation: 'สัญญาณตลาดโดยรวมอยู่ในโซนสร้างสรรค์ เหมาะกับการติดตามโอกาส แต่ไม่ควรตีความเป็นสัญญาณซื้ออัตโนมัติ', actions: ['รอจังหวะเข้าที่มีเหตุผล', 'เน้นสินทรัพย์พื้นฐานแข็งแกร่ง', 'ติดตามความผันผวนก่อนเพิ่มน้ำหนัก'] }
        : composite >= 60
          ? { label: 'เป็นกลาง', phase: 'สมดุล', className: 'mood-neutral', explanation: 'ข้อมูลตลาดให้สัญญาณผสม ยังไม่มีทิศทางที่ชัดเจน ผู้ใช้ควรอ่านร่วมกับแนวโน้มราคา ข่าว และความเสี่ยงรายสินทรัพย์', actions: ['ถือแผนเดิมอย่างมีวินัย', 'รอการยืนยันแนวโน้ม', 'คัดเลือกเฉพาะสินทรัพย์ที่ข้อมูลครบ'] }
          : composite >= 40
            ? { label: 'ระมัดระวัง', phase: 'ความเสี่ยงสูง', className: 'mood-caution', explanation: 'ภาวะตลาดยังมีความผันผวน ควรเพิ่มความระมัดระวังในการลงทุนและหลีกเลี่ยงการเปิดสถานะขนาดใหญ่', actions: ['ลดขนาดการลงทุน', 'รอการยืนยันแนวโน้ม', 'ติดตามข่าวเศรษฐกิจ'] }
            : { label: 'เชิงลบ', phase: 'Risk-Off', className: 'mood-off', explanation: 'ภาวะตลาดสะท้อนแรงกดดันหรือความเสี่ยงสูงกว่าปกติ ควรให้ความสำคัญกับการปกป้องเงินทุนมากกว่าการเร่งหาผลตอบแทน', actions: ['ลดความเสี่ยงของพอร์ต', 'หลีกเลี่ยงสินทรัพย์ผันผวนสูง', 'รอให้ความเสี่ยงลดลงก่อนเพิ่มสถานะ'] };
  const evidence = (marketCondition?.evidence ?? []).slice(0, 4);
  const providerNote = sentiment?.note_th ?? marketCondition?.state_th ?? l.unavailableNote;
  const driverDefinitions = [
    { key: 'sp500', label: 'S&P500', symbols: ['^GSPC'], explanation: 'สะท้อนทิศทางหุ้นสหรัฐและความต้องการรับความเสี่ยงของตลาดโลก' },
    { key: 'set', label: 'SET', symbols: ['^SET.BK', 'SET.BK'], explanation: 'สะท้อนบรรยากาศตลาดหุ้นไทยและแรงซื้อขายในประเทศ' },
    { key: 'usdthb', label: 'USD/THB', symbols: ['USDTHB=X', 'THB=X'], explanation: 'ค่าเงินบาทมีผลต่อเงินทุนต่างชาติ ต้นทุนนำเข้า และกำไรของบางอุตสาหกรรม' },
    { key: 'gold', label: 'Gold', symbols: ['GC=F', 'GOLD'], explanation: 'ทองคำมักสะท้อนความต้องการสินทรัพย์ปลอดภัยและมุมมองต่อเงินเฟ้อ' },
    { key: 'oil', label: 'Oil', symbols: ['CL=F', 'BZ=F'], explanation: 'น้ำมันมีผลต่อต้นทุน พลังงาน เงินเฟ้อ และหุ้นกลุ่มพลังงาน' },
    { key: 'vix', label: 'VIX', symbols: ['^VIX', 'VIX'], explanation: 'ดัชนีความผันผวน ใช้ดูระดับความกังวลของตลาด' },
  ];
  const drivers = driverDefinitions.map((definition) => ({ definition, metric: metrics.find((item) => definition.symbols.includes(item.symbol) || item.key === definition.key || item.label === definition.label) }));
  const thaiPercent = (value: number | null | undefined) => value == null ? 'ไม่มีข้อมูล' : `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  const thaiTime = (value: string | undefined) => value ? new Date(value).toLocaleString() : 'ไม่มีข้อมูล';

  return <Panel title="ภาวะตลาด" icon={<Scale size={18} />}><div className="market-mood-card"><div className={'mood-gauge ' + mood.className} aria-label={`คะแนนภาวะตลาด ${composite == null ? 'ไม่พร้อมใช้งาน' : composite}`}><span>คะแนนรวม</span><b>{composite == null ? 'ไม่มีข้อมูล' : composite}</b><small>{mood.phase}</small></div><div className="market-mood-copy"><p className="market-mood-kicker">ภาวะตลาด</p><h3>{mood.label}</h3><span className={'market-mood-status ' + mood.className}>{mood.phase}</span><div className="market-mood-explain"><h4>ความหมาย</h4><p>{mood.explanation}</p><p>{providerNote}</p></div><div className="market-mood-actions"><h4>สิ่งที่ AI แนะนำ</h4><ul>{mood.actions.map((item) => <li key={item}>{item}</li>)}</ul></div><div className="mt-3 flex flex-wrap gap-2">{(evidence.length ? evidence : ['ยังไม่มีหลักฐานจากผู้ให้บริการ']).map((item) => <span className="reason-chip" key={item}>{item}</span>)}</div></div></div><div className="market-drivers-header"><h3>ปัจจัยที่ส่งผล</h3><p>อ่านปัจจัยหลักร่วมกันเพื่อเข้าใจว่าคะแนนภาวะตลาดได้รับแรงหนุนหรือแรงกดดันจากด้านใด</p></div><div className="market-grid mt-3">{drivers.map(({ definition, metric }) => { const change = metric?.change_percent ?? null; const positive = change != null && change >= 0; const direction = change == null ? 'ไม่มีข้อมูล' : positive ? 'เพิ่มขึ้น' : 'ลดลง'; return <div className="metric-card market-driver-card" key={definition.key}><div className="flex items-center justify-between gap-2"><span className="text-sm font-semibold text-white">{definition.label}</span><span className={change == null ? 'text-terminal-muted' : positive ? 'text-terminal-green' : 'text-terminal-red'}>{direction} {thaiPercent(change)}</span></div><p className="mt-2 text-lg font-semibold text-terminal-text">{metric?.value == null ? 'ไม่พร้อมใช้งาน' : formatNumber(metric.value, metric.symbol === '^TNX' ? 2 : 2)}</p><p className="mt-1 text-xs leading-5 text-terminal-muted">{definition.explanation}</p><p className="mt-1 text-xs text-terminal-muted">{metric?.provider ?? marketCondition?.provider ?? 'ผู้ให้บริการ'} | {thaiTime(metric?.timestamp)}</p>{metric?.error && <p className="mt-1 text-xs text-terminal-amber">{metric.error}</p>}</div>; })}</div>{marketCondition?.unavailable?.length ? <p className="mt-3 text-xs text-terminal-muted">ข้อมูลจากผู้ให้บริการยังไม่พร้อม: {marketCondition.unavailable.join(', ')}</p> : null}</Panel>;
}

function NewsPanel({ t, l, news, expanded = false }: { t: Translation; l: typeof labels.th; news: NewsImpactResponse | null; expanded?: boolean }) {
  const items = news?.items ?? [];
  const tagFor = (headline: string) => /nvidia|semiconductor|chip|ai/i.test(headline) ? 'AI' : /oil|energy|gas/i.test(headline) ? 'Energy' : /bitcoin|crypto/i.test(headline) ? 'Crypto' : /fed|rate|inflation|dollar|macro/i.test(headline) ? 'Macro' : news?.symbol?.endsWith('.BK') ? 'TH' : 'US';

  return <Panel title="Latest News" icon={<Newspaper size={18} />}><div className="news-scroll-panel"><div className="news-sticky-header"><span>Latest News</span><small>{news?.symbol ?? 'Selected asset'} | {items.length} stories</small></div>{items.length ? <div className="grid gap-3 p-3">{items.map((item) => { const sentimentText = String(item.sentiment || 'Neutral'); const tag = tagFor(item.headline); const toneClass = /bull|positive/i.test(sentimentText) ? 'text-terminal-green' : /bear|negative/i.test(sentimentText) ? 'text-terminal-red' : 'text-terminal-amber'; const country = news?.symbol?.endsWith('.BK') ? 'TH' : 'US'; return <article className="news-card pro-news-card" key={item.headline + '-' + (item.url ?? item.source)}><div className="flex items-start justify-between gap-3"><div className="min-w-0"><div className="mb-2 flex flex-wrap gap-2"><span className="news-tag">{tag}</span><span className="news-tag muted">{country}</span><span className="news-tag muted">{item.source || 'Source unavailable'}</span></div><p className="text-sm font-semibold leading-6 text-white">{item.headline}</p><p className="mt-2 text-xs text-terminal-muted">{item.published_at ? formatTime(item.published_at) : 'Published time unavailable'}</p></div>{item.url && <a className="icon-button" href={item.url} target="_blank" rel="noreferrer" aria-label="Open original article"><ExternalLink size={14} /></a>}</div><p className="mt-3 text-sm leading-6 text-terminal-text">{item.ai_explanation || 'Unavailable from provider'}</p><p className={'mt-2 text-sm ' + toneClass}>{l.sentiment}: {sentimentText}</p>{(expanded || item.risk_warning) && <p className="mt-2 text-sm text-amber-100">{l.riskWarning}: {item.risk_warning || 'Unavailable from provider'}</p>}</article>; })}</div> : <EmptyState message={news?.message_th ?? news?.message ?? 'Unavailable from provider'} />}</div><p className="mt-3 text-xs text-terminal-muted">{l.unavailableNote}</p></Panel>;
}

function QuickAssistantPanel({ l, selectedSymbol, quote, question, setQuestion, ask }: { l: typeof labels.th; selectedSymbol: string; quote: AssetQuote | null; question: string; setQuestion: (q: string) => void; ask: () => void }) {
  const prompts = contextPrompts(selectedSymbol, quote).slice(0, 3);
  return <Panel title="PIA Quick Assistant" icon={<Brain size={18} />}><div className="fs300-quick-assistant"><div><span>{l.selectedAssetFirst}</span><strong>{selectedSymbol}</strong></div><select className="input-shell" value={question || prompts[0] || ''} onChange={(event) => setQuestion(event.target.value)} aria-label={l.question}>{prompts.map((prompt) => <option key={prompt} value={prompt}>{prompt}</option>)}</select><div className="grid gap-2">{prompts.map((prompt) => <button className="watch-button text-left" key={prompt} onClick={() => setQuestion(prompt)}>{prompt}</button>)}</div><button className="about-button w-full" onClick={ask}><Brain size={15} />{l.ask}</button><p>{l.assistantContext}</p></div></Panel>;
}

function AssistantSection({ l, selectedSymbol, quote, question, setQuestion, answer, history, ask }: { l: typeof labels.th; selectedSymbol: string; quote: AssetQuote | null; question: string; setQuestion: (q: string) => void; answer: string; history: Array<{ question: string; response: AssistantResponse }>; ask: () => void }) { const prompts = contextPrompts(selectedSymbol, quote); const iconFor = (prompt: string) => /dividend/i.test(prompt) ? 'Dividend' : /trend|momentum|peer/i.test(prompt) ? 'Trend' : /risk|invalidate/i.test(prompt) ? 'Risk' : /news|event/i.test(prompt) ? 'News' : /valuation|growth/i.test(prompt) ? 'Valuation' : 'PIA'; return <Panel title={l.assistant} icon={<Brain size={18} />}><p className="mb-3 rounded-md bg-terminal-panel2 p-3 text-sm text-terminal-muted">{l.selectedAssetFirst}: <span className="font-semibold text-white">{selectedSymbol}</span>. {l.assistantContext}</p><p className="mb-2 text-xs font-semibold uppercase tracking-[0.14em] text-terminal-muted">Suggested Questions</p><div className="mb-3 grid gap-2 md:grid-cols-3">{prompts.map((prompt) => <button className="suggested-question-card" key={prompt} onClick={() => setQuestion(prompt)}><span>{iconFor(prompt)}</span><b>{prompt}</b></button>)}</div><textarea className="input-shell min-h-28" value={question} onChange={(event) => setQuestion(event.target.value)} aria-label={l.question} /><button className="about-button mt-3" onClick={ask}>{l.ask}</button>{answer && <p className="mt-4 rounded-md bg-terminal-panel2 p-4 text-sm leading-6 text-white">{answer}</p>}{history[0] && <div className="mt-4 grid gap-3"><h3 className="text-sm font-semibold text-white">{l.conversationHistory}</h3>{history.map((item) => <div className="rounded-md bg-terminal-panel2 p-3" key={item.question + '-' + item.response.answer.slice(0, 20)}><p className="text-sm font-semibold text-terminal-cyan">{item.question}</p><p className="mt-2 text-sm leading-6 text-terminal-text">{item.response.answer}</p><p className="mt-2 text-xs text-terminal-muted">{l.reasoningReferences}: {item.response.facts_used.join(', ')}</p><p className="mt-2 text-xs text-terminal-muted">{l.followUp}: {item.response.follow_up_questions.join(' | ')}</p></div>)}</div>}</Panel>; }
function PortfolioSection({ l, evaluation, portfolio, newHolding, setNewHolding, addHolding, initialCash, setInitialCash, newTransaction, setNewTransaction, addTransaction, resetPortfolio }: { l: typeof labels.th; evaluation: PortfolioEvaluationResponse | null; portfolio: PortfolioHolding[]; newHolding: PortfolioHolding; setNewHolding: (h: PortfolioHolding) => void; addHolding: () => void; initialCash: number; setInitialCash: (value: number) => void; newTransaction: PortfolioTransaction; setNewTransaction: (value: PortfolioTransaction) => void; addTransaction: () => void; resetPortfolio: () => void }) {
  const allocation = (evaluation?.items ?? []).filter((item) => item.allocation_percent != null).map((item) => ({ name: item.symbol, value: item.allocation_percent ?? 0, count: item.quantity }));
  const sectorAllocation = (evaluation?.sector_allocation ?? []).map((item) => ({ name: item.sector, value: item.allocation_percent }));
  const transactions = evaluation?.transaction_history ?? [];
  const ranked = [...(evaluation?.items ?? [])].filter((item) => item.gain_loss_percent != null).sort((a, b) => (b.gain_loss_percent ?? -999) - (a.gain_loss_percent ?? -999));
  const topWinner = ranked[0];
  const topLoser = ranked[ranked.length - 1];
  const assetTypeAllocation = (evaluation?.items ?? []).reduce<Record<string, number>>((acc, item) => { const key = item.asset_type ?? 'Unknown'; acc[key] = (acc[key] ?? 0) + (item.allocation_percent ?? 0); return acc; }, {});
  return <Panel title={l.portfolio} icon={<WalletCards size={18} />}><div className="grid gap-3 lg:grid-cols-[160px_120px_1fr_120px_120px_140px_auto_auto]"><input aria-label="Initial cash" className="input-shell" type="number" value={initialCash} onChange={(e) => setInitialCash(Number(e.target.value))} /><select className="input-shell" value={newTransaction.side} onChange={(e) => setNewTransaction({ ...newTransaction, side: e.target.value as 'buy' | 'sell' })}><option value="buy">Buy</option><option value="sell">Sell</option></select><input aria-label="Ticker" className="input-shell" value={newTransaction.symbol} onChange={(e) => setNewTransaction({ ...newTransaction, symbol: e.target.value.toUpperCase() })} /><input aria-label={l.quantity} className="input-shell" type="number" value={newTransaction.quantity} onChange={(e) => setNewTransaction({ ...newTransaction, quantity: Number(e.target.value) })} /><input aria-label="Price" className="input-shell" type="number" value={newTransaction.price} onChange={(e) => setNewTransaction({ ...newTransaction, price: Number(e.target.value) })} /><input aria-label="Date" className="input-shell" type="date" value={newTransaction.date} onChange={(e) => setNewTransaction({ ...newTransaction, date: e.target.value })} /><button className="about-button" disabled={!newTransaction.symbol || newTransaction.quantity <= 0 || newTransaction.price < 0} onClick={addTransaction}>{l.add}</button><button className="about-button" onClick={resetPortfolio}>{l.remove}</button></div><details className="mt-3 rounded-md border border-terminal-border bg-terminal-panel2 p-3"><summary className="cursor-pointer text-sm font-semibold text-terminal-muted">Legacy holding entry</summary><div className="mt-3 grid gap-3 md:grid-cols-5"><input aria-label="Ticker" className="input-shell" value={newHolding.symbol} onChange={(e) => setNewHolding({ ...newHolding, symbol: e.target.value.toUpperCase() })} /><input aria-label={l.quantity} className="input-shell" type="number" value={newHolding.quantity} onChange={(e) => setNewHolding({ ...newHolding, quantity: Number(e.target.value) })} /><input aria-label={l.averageCost} className="input-shell" type="number" value={newHolding.averageCost} onChange={(e) => setNewHolding({ ...newHolding, averageCost: Number(e.target.value) })} /><input aria-label="Currency" className="input-shell" value={newHolding.currency} onChange={(e) => setNewHolding({ ...newHolding, currency: e.target.value.toUpperCase() })} /><button className="about-button" disabled={!newHolding.symbol || newHolding.quantity <= 0 || newHolding.averageCost <= 0} onClick={addHolding}>{l.addHolding}</button></div></details><div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><StatusTile label="Cash" value={formatCompactNumber(evaluation?.cash_balance)} /><StatusTile label="Buying Power" value={formatCompactNumber(evaluation?.cash_balance)} /><StatusTile label="Market Value" value={formatCompactNumber(evaluation?.total_value)} /><StatusTile label="Today's P/L" value={formatPercent(evaluation?.daily_return_percent)} /><StatusTile label={l.unrealizedPl} value={formatCompactNumber(evaluation?.total_gain_loss)} /><StatusTile label={l.realizedPl} value={formatCompactNumber(evaluation?.realized_gain_loss)} /><StatusTile label="Total Return" value={formatPercent(evaluation?.portfolio_return_percent ?? evaluation?.total_gain_loss_percent)} /><StatusTile label="Portfolio Value" value={formatCompactNumber(evaluation?.total_equity)} /></div><div className="mt-4 grid gap-4 xl:grid-cols-[1fr_320px]"><div className="grid gap-3">{portfolio.length ? evaluation?.items.map((item) => <div className="position-card" key={item.symbol}><div className="grid gap-2 md:grid-cols-7"><b>{item.symbol}</b><span>{l.quantity}: {item.quantity}</span><span>{l.averageCost}: {formatNumber(item.average_cost)}</span><span>Price: {formatNumber(item.last_price)}</span><span>{l.currentValue}: {item.market_value == null ? 'Unavailable from provider' : `${formatNumber(item.market_value)} ${item.currency}`}</span><span>{l.unrealizedPl}: {formatPercent(item.gain_loss_percent)}</span><span>{l.allocation}: {formatPercent(item.allocation_percent)}</span></div>{item.error && <p className="mt-2 text-xs text-terminal-amber">{item.error}</p>}</div>) : <EmptyState message={l.noData} />}</div><div className="rounded-md bg-terminal-panel2 p-3"><h3 className="text-sm font-semibold text-white">{l.allocation}</h3><div className="h-48">{allocation.length ? <ResponsiveContainer><PieChart><Tooltip formatter={(value, name, item) => [`${formatNumber(Number(value))}% | ${l.count} ${item.payload.count}`, name]} contentStyle={{ background: '#0a101c', border: '1px solid #1e2b3f', color: '#d9e7ff' }} /><Pie data={allocation} dataKey="value" nameKey="name" innerRadius={46} outerRadius={76} label={({ name, value }) => `${name} ${formatNumber(value)}%`}>{allocation.map((_, index) => <Cell key={index} fill={pieColors[index % pieColors.length]} />)}</Pie></PieChart></ResponsiveContainer> : <EmptyState message={l.noData} />}</div><p className="text-xs text-terminal-muted">{l.sectorAllocation}: {sectorAllocation.map((item) => `${item.name} ${formatNumber(item.value)}%`).join(' | ') || 'Unavailable from provider'}</p><p className="mt-2 text-xs text-terminal-muted">Country Allocation: Unavailable from provider</p><p className="mt-2 text-xs text-terminal-muted">Asset Allocation: {Object.entries(assetTypeAllocation).map(([name, value]) => `${name} ${formatNumber(value)}%`).join(' | ') || 'Unavailable from provider'}</p></div></div><div className="mt-4 grid gap-3 md:grid-cols-4"><StatusTile label="Top Winner" value={topWinner ? `${topWinner.symbol} ${formatPercent(topWinner.gain_loss_percent)}` : 'Unavailable'} /><StatusTile label="Top Loser" value={topLoser ? `${topLoser.symbol} ${formatPercent(topLoser.gain_loss_percent)}` : 'Unavailable'} /><StatusTile label={l.riskWarning} value={evaluation?.risk_score == null ? 'Unavailable' : `${evaluation.risk_score}/10`} /><StatusTile label={l.diversification} value={evaluation?.diversification_score == null ? 'Unavailable' : `${evaluation.diversification_score}/100`} /></div><div className="mt-4 rounded-md bg-terminal-panel2 p-3"><h3 className="mb-2 text-sm font-semibold text-white">{l.transactions}</h3>{transactions.length ? <div className="grid gap-2">{transactions.map((tx, index) => <p className="text-sm text-terminal-muted" key={`${tx.symbol}-${tx.side}-${index}`}>{String(tx.date ?? '')} | {String(tx.side).toUpperCase()} | {String(tx.symbol)} | {formatNumber(Number(tx.quantity))} @ {formatNumber(Number(tx.price))}</p>)}</div> : <EmptyState message={l.noData} />}</div><p className="mt-4 text-sm text-terminal-muted">{l.aiComment}: {l.portfolioCaution}. {evaluation?.analytics_unavailable_reason} {evaluation?.currency_conversion}</p></Panel>;
}function CalendarSection({ l, language, calendar }: { l: typeof labels.th; language: Language; calendar: CalendarResponse | null }) { const events = calendar?.events ?? []; return <Panel title={l.calendar} icon={<CalendarDays size={18} />}><div className="grid gap-3 md:grid-cols-2">{events.length ? events.map((event) => <div className="rounded-md bg-terminal-panel2 p-3" key={`${event.date}-${event.name}`}><p className="font-semibold text-white">{event.date} | {event.name}</p><p className="mt-2 text-sm text-terminal-muted">{event.region} | {l.impact}: {event.impact_level}</p><p className="mt-2 text-sm leading-6">{language === 'th' ? event.note_th : event.note_en}</p><p className="mt-2 text-xs text-terminal-cyan">{event.related_assets.join(', ')}</p></div>) : <EmptyState message={(language === 'th' ? calendar?.message_th : calendar?.message) ?? l.noData} />}</div><p className="mt-3 text-xs text-terminal-muted">{l.unavailableNote}</p></Panel>; }


function AboutDialog({ t, open, onClose }: { t: Translation; open: boolean; onClose: () => void }) {
  const [activeSection, setActiveSection] = React.useState('about');
  React.useEffect(() => { if (open) setActiveSection('about'); }, [open]);
  if (!open) return null;

  const isThai = t === translations.th;
  const glossary = isThai
    ? [['Opportunity Score', 'คะแนนคัดกรองที่สรุปสัญญาณตลาดจริงหลายด้านเพื่อช่วยเลือกสินทรัพย์ไปวิเคราะห์ต่อ'], ['Momentum', 'แรงเคลื่อนไหวของราคาในช่วงล่าสุด'], ['Trend', 'ทิศทางหลักของราคาในช่วงเวลาหนึ่ง'], ['Relative Strength', 'ความแข็งแรงของสินทรัพย์เมื่อเทียบกับสินทรัพย์อื่นหรือตลาด'], ['Volatility', 'ระดับความผันผวนของราคา'], ['Risk', 'โอกาสเกิดผลลัพธ์ไม่พึงประสงค์หรือขาดทุน'], ['Support', 'บริเวณราคาที่มักมีแรงซื้อช่วยพยุง'], ['Resistance', 'บริเวณราคาที่มักมีแรงขายกดดัน'], ['Market Structure', 'รูปแบบการทำจุดสูง จุดต่ำ และจังหวะของตลาด'], ['Moving Average', 'เส้นค่าเฉลี่ยราคาที่ช่วยให้เห็นแนวโน้มชัดขึ้น'], ['RSI', 'ตัวชี้วัดภาวะแรงซื้อหรือแรงขายมากเกินไป'], ['MACD', 'ตัวชี้วัดโมเมนตัมและการเปลี่ยนจังหวะแนวโน้ม'], ['Sector Rotation', 'การโยกเงินระหว่างกลุ่มอุตสาหกรรม'], ['Market Breadth', 'ภาพรวมว่ามีสินทรัพย์จำนวนมากหรือน้อยที่ร่วมขยับไปทางเดียวกัน']]
    : [['Opportunity Score', 'A screening score that summarizes multiple real market signals for further research.'], ['Momentum', 'How strongly price has been moving recently.'], ['Trend', 'The main direction of price over a period of time.'], ['Relative Strength', 'How an asset performs compared with peers or the broader market.'], ['Volatility', 'How widely price moves up and down.'], ['Risk', 'The chance of an unfavorable outcome or loss.'], ['Support', 'A price area where buying interest may appear.'], ['Resistance', 'A price area where selling pressure may appear.'], ['Market Structure', 'The pattern of highs, lows, and price behavior.'], ['Moving Average', 'An average price line that smooths noise and helps show trend.'], ['RSI', 'A momentum indicator often used to spot stretched buying or selling.'], ['MACD', 'A momentum indicator used to observe trend shifts.'], ['Sector Rotation', 'Money moving from one industry group to another.'], ['Market Breadth', 'How many assets are participating in a market move.']];
  const sections = [
    { id: 'about', icon: <Info size={17} />, title: isThai ? 'เกี่ยวกับ Market Pulse AI' : 'About Market Pulse AI', body: isThai ? ['Market Pulse AI คือแดชบอร์ดข้อมูลการลงทุนที่ช่วยให้นักลงทุนติดตามตลาดการเงินทั่วโลกด้วยข้อมูลตลาดจริงและการวิเคราะห์ด้วย AI ที่โปร่งใส', 'แพลตฟอร์มนี้สนับสนุนการวิจัยและการศึกษาด้านการลงทุน ไม่ใช่ระบบซื้อขายอัตโนมัติ'] : ['Market Pulse AI is an investment intelligence dashboard designed to help investors monitor global financial markets using real market data and transparent AI-assisted analysis.', 'The platform supports investment research and education. It is not an automated trading system.'] },
    { id: 'design', icon: <Sparkles size={17} />, title: isThai ? 'ปรัชญาการออกแบบ' : 'Design Philosophy', body: isThai ? ['ระบบเน้นข้อมูลจริง ความโปร่งใส และการอธิบายเหตุผลมากกว่าการแสดงตัวเลขเพียงอย่างเดียว', 'เมื่อข้อมูลไม่พร้อม ระบบจะแสดงสถานะอย่างตรงไปตรงมาแทนการเติมข้อมูลสมมติ'] : ['The product emphasizes real data, transparency, and explanation rather than showing numbers alone.', 'When data is unavailable, the interface says so clearly instead of filling gaps with synthetic values.'] },
    { id: 'zero-mock', icon: <ShieldCheck size={17} />, title: isThai ? 'นโยบาย Zero Mock' : 'Zero Mock Policy', body: isThai ? ['Market Pulse AI ไม่สร้างราคา กราฟ ข่าว งบการเงิน หรือคำแนะนำจาก AI แบบสมมติ', 'หากข้อมูลสดไม่พร้อมใช้งาน ระบบจะแสดงคำว่า Unavailable แทนการสร้างข้อมูลสังเคราะห์'] : ['Market Pulse AI never fabricates prices, charts, news, financial statements, or AI recommendations.', 'If live data is unavailable, the system explicitly reports Unavailable instead of generating synthetic data.'] },
    { id: 'score', icon: <BarChart3 size={17} />, title: isThai ? 'อธิบาย Opportunity Score' : 'Opportunity Score Explained', body: isThai ? ['Opportunity Score มีช่วง 0-100 และไม่ได้ถูกสร้างแบบสุ่ม', 'คะแนนนี้เป็นโมเดล heuristic แบบถ่วงน้ำหนักเพื่อสรุปสัญญาณตลาดหลายด้านเป็นคะแนนเดียว โดยไม่เปิดเผยรายละเอียดเชิง proprietary', 'Opportunity Score เป็นเครื่องมือคัดกรอง ไม่ได้ทำนายราคาในอนาคต และไม่ใช่คำแนะนำการลงทุน'] : ['Opportunity Score ranges from 0-100 and is not generated randomly.', 'It is a weighted heuristic model that summarizes multiple market signals into one score without exposing proprietary implementation details.', 'Opportunity Score is a screening tool. It does not predict future prices and is not investment advice.'] },
    { id: 'committee', icon: <Brain size={17} />, title: isThai ? 'คณะกรรมการ AI' : 'AI Committee', body: isThai ? ['Market Pulse AI แสดงหลายมุมมอง เช่น Chief Investment AI, Technical AI, Fundamental AI, Macro AI, News AI และ Risk AI', 'มุมมองเหล่านี้ช่วยให้เห็นภาพประกอบกัน ไม่ใช่คำทำนายเดียว'] : ['Market Pulse AI presents multiple viewpoints, including Chief Investment AI, Technical AI, Fundamental AI, Macro AI, News AI, and Risk AI.', 'These perspectives are complementary and should not be read as a single prediction.'] },
    { id: 'sources', icon: <Globe2 size={17} />, title: isThai ? 'แหล่งข้อมูล' : 'Data Sources', body: isThai ? ['ตัวอย่างแหล่งข้อมูล ได้แก่ Yahoo Finance, Public Market APIs, ชุดข้อมูลทางการเงิน และ production providers', 'ผู้ให้บริการที่ใช้งานขึ้นอยู่กับประเภทสินทรัพย์และความพร้อมของตลาด'] : ['Example sources include Yahoo Finance, public market APIs, financial datasets, and production providers.', 'The active provider depends on asset type and market availability.'] },
    { id: 'limitations', icon: <AlertTriangle size={17} />, title: isThai ? 'ข้อจำกัด' : 'Limitations', body: isThai ? ['Market Pulse AI ไม่รับประกันผลตอบแทน ราคาในอนาคต หรือความสำเร็จในการลงทุน', 'เหตุการณ์ตลาดที่ไม่คาดคิดอาจทำให้สัญญาณในอดีตใช้ไม่ได้'] : ['Market Pulse AI cannot guarantee future returns, future prices, or investment success.', 'Unexpected market events may invalidate historical signals.'] },
    { id: 'disclaimer', icon: <Scale size={17} />, title: isThai ? 'คำเตือนการลงทุน' : 'Investment Disclaimer', body: isThai ? ['ข้อมูลทั้งหมดจัดทำเพื่อการศึกษาและการวิจัยเท่านั้น', 'ผู้ใช้ยังคงรับผิดชอบการตัดสินใจลงทุนของตนเอง และควรกำหนดแผนบริหารความเสี่ยงก่อนลงทุน'] : ['All information is for education and research only.', 'Users remain responsible for their own investment decisions and should define a risk plan before investing.'] },
    { id: 'glossary', icon: <BookOpen size={17} />, title: isThai ? 'อภิธานศัพท์การเงิน' : 'Financial Glossary', body: [], rows: glossary },
    { id: 'founder', icon: <Sparkles size={17} />, title: isThai ? 'ผู้ก่อตั้ง' : 'Founder', body: [], rows: [[t.founder, 'Ponrat Saripan'], ['Project', 'Market Pulse AI'], [t.version, 'v1.0.0'], [isThai ? 'รุ่นเผยแพร่' : 'Release', 'Production']] },
  ];

  const toggleSection = (id: string) => setActiveSection((current) => current === id ? '' : id);
  const handleAccordionKeyDown = (event: React.KeyboardEvent<HTMLButtonElement>, id: string) => { if (event.key === 'Enter' || event.key === ' ') { event.preventDefault(); toggleSection(id); } };

  return <div className="modal-backdrop" role="dialog" aria-modal="true" aria-labelledby="about-title"><div className="about-dialog about-dialog-expanded"><div className="about-dialog-header"><div><p className="about-kicker">{isThai ? 'ศูนย์ความรู้' : 'Knowledge Center'}</p><h2 id="about-title">About Market Pulse AI</h2><p>{isThai ? 'แดชบอร์ดข้อมูลการลงทุนระดับมืออาชีพ' : 'Professional Investment Intelligence Dashboard'}</p><p>{t.version}: v1.0.0</p></div><button className="icon-button" onClick={onClose} aria-label={isThai ? 'ปิด' : 'Close'}><X size={18} /></button></div><div className="about-accordion">{sections.map((section) => { const active = activeSection === section.id; return <section className="about-accordion-item" key={section.id}><button className="about-accordion-trigger" type="button" aria-expanded={active} aria-controls={`knowledge-section-${section.id}`} onClick={() => toggleSection(section.id)} onKeyDown={(event) => handleAccordionKeyDown(event, section.id)}><span>{section.icon}</span><strong>{section.title}</strong><ChevronDown className={active ? 'about-chevron about-chevron-open' : 'about-chevron'} size={16} /></button><div id={`knowledge-section-${section.id}`} className={active ? 'about-accordion-panel about-accordion-panel-open' : 'about-accordion-panel'} hidden={!active}><div className="about-accordion-panel-inner">{section.body.map((paragraph) => <p key={paragraph}>{paragraph}</p>)}{section.rows?.length ? <div className="about-info-grid">{section.rows.map(([label, value]) => <InfoRow key={label} label={label} value={value} />)}{section.id === 'founder' && <><InfoRow label={t.repository} value={repoUrl} href={repoUrl} /><InfoRow label={t.license} value="MIT License" /></>}</div> : null}</div></div></section>; })}</div></div></div>;
}
function InfoRow({ label, value, href }: { label: string; value: string; href?: string }) { return <div className="mt-3 flex flex-col gap-1 rounded-md bg-terminal-panel2 p-3 sm:flex-row sm:items-center sm:justify-between"><span className="text-xs uppercase tracking-[0.14em] text-terminal-muted">{label}</span>{href ? <a className="text-terminal-cyan" href={href} target="_blank" rel="noreferrer">{value}</a> : <span className="font-semibold text-white">{value}</span>}</div>; }
function Footer({ t }: { t: Translation }) { const l = t === translations.th ? labels.th : labels.en; return <footer className="rounded-md border border-terminal-border bg-terminal-panel px-4 py-3 text-sm leading-6 text-terminal-muted"><div className="flex flex-col gap-2 lg:flex-row lg:items-center lg:justify-between"><p><span className="font-semibold text-white">{t.notFinancialAdvice}.</span> {t.disclaimerText}</p><div className="flex flex-wrap gap-3 text-terminal-cyan"><span>© 2026 Market Pulse AI</span><span>Powered by PIA™</span><span>{l.allRightsReserved}</span><a href={repoUrl} target="_blank" rel="noreferrer">GitHub</a></div></div></footer>; }
function Panel({ title, icon, children }: { title: string; icon: React.ReactNode; children: React.ReactNode }) { const help = panelHelpText(title); return <section className={`panel-card professional-panel ${panelToneClass(title)}`}><div className="professional-header">{icon}<h2>{title}</h2>{help && <EducationHint text={help} />}</div>{children}</section>; }
function panelToneClass(title: string): string { const value = title.toLowerCase(); if (value.includes('financial') || value.includes('?????????')) return 'panel-financial'; if (value.includes('chart') || value.includes('????')) return 'panel-chart'; if (value.includes('data source') || value.includes('???????????')) return 'panel-data'; if (value.includes('asset console') || value.includes('??????????')) return 'panel-console'; if (value.includes('watchlist') || value.includes('????????????')) return 'panel-watchlist'; return ''; }
function EducationHint({ text }: { text: string }) { return <button className="education-hint" type="button" title={text} aria-label={text}><Info size={12} /></button>; }
function panelHelpText(title: string): string | null { const value = title.toLowerCase(); if (value.includes('committee') || value.includes('คณะกรรมการ')) return 'AI Committee combines several educational viewpoints. It is not a single prediction or trading instruction.'; if (value.includes('risk') || value.includes('ความเสี่ยง')) return 'Risk Analysis highlights uncertainty, downside, and planning considerations. It is not a guarantee.'; if (value.includes('sentiment') || value.includes('ภาวะตลาด')) return 'Market Mood คือการสรุปภาพรวมของสภาวะตลาดจากข้อมูลหลายด้าน เช่น แนวโน้มราคา ความผันผวน ข่าวเศรษฐกิจ และปัจจัยมหภาค คะแนนนี้เป็นข้อมูลประกอบการวิเคราะห์ ไม่ใช่คำแนะนำในการซื้อหรือขาย'; if (value.includes('financial') || value.includes('งบการเงิน')) return 'Financial Health uses available provider fundamentals. Missing values remain unavailable rather than estimated.'; return null; }
function StatusRow({ label, value }: { label: string; value: string }) { return <div className="mb-2 flex items-center justify-between gap-3 rounded-md bg-terminal-panel2 px-3 py-2"><span className="text-xs uppercase tracking-[0.12em] text-terminal-muted">{label}</span><span className="text-sm font-semibold text-white">{value}</span></div>; }
function StatusTile({ label, value }: { label: string; value: string }) { return <div className="status-tile-pro"><p>{label}</p><b className={statusBadgeClass(value)}>{value}</b><span className="signal-strength" aria-hidden="true"><i style={{ width: signalStrength(value) + '%' }} /></span></div>; }
function statusBadgeClass(value: string): string { const text = value.toLowerCase(); if (/buy|bull|positive|healthy|excellent|good|contained|low/.test(text)) return 'status-badge status-positive'; if (/reduce|sell|avoid|bear|weak|high|risk|caution/.test(text)) return 'status-badge status-warning'; if (/hold|neutral|moderate|medium|average|stable/.test(text)) return 'status-badge status-neutral'; if (/unavailable|await|wait|n\/a/.test(text)) return 'status-badge status-muted'; return 'status-badge status-ai'; }
function signalStrength(value: string): number { const text = value.toLowerCase(); if (/strong|excellent|buy/.test(text)) return 88; if (/positive|good|contained|medium/.test(text)) return 68; if (/neutral|hold|moderate|stable/.test(text)) return 52; if (/high|weak|reduce|sell|avoid|risk/.test(text)) return 38; return 24; }
function ListBlock({ title, items }: { title: string; items?: string[] }) { return <div><p className="mb-2 text-xs font-semibold uppercase tracking-[0.14em] text-terminal-muted">{title}</p><ul className="space-y-2">{(items ?? []).map((item) => <li className="rounded-md bg-terminal-panel2 px-3 py-2 text-sm leading-6 text-terminal-text" key={item}>{item}</li>)}</ul></div>; }
function EmptyState({ message }: { message: string }) { return <div className="executive-empty-state"><Info size={15} aria-hidden="true" /><span>Unavailable</span><p>{message}</p></div>; }

ReactDOM.createRoot(document.getElementById('root')!).render(<React.StrictMode><App /></React.StrictMode>);
